{
  "files": [
    {
      "path": "factory-system/package.json",
      "content": "{
  "name": "factory-system",
  "version": "1.0.0",
  "description": "Factory system core layout",
  "main": "dist/index.js",
  "types": "dist/index.d.ts",
  "scripts": {
    "build": "tsc"
  },
  "devDependencies": {
    "typescript": "^5.0.0"
  }
}"
    },
    {
      "path": "factory-system/tsconfig.json",
      "content": "{
  "compilerOptions": {
    "target": "ES2020",
    "module": "CommonJS",
    "outDir": "./dist",
    "rootDir": "./src",
    "strict": true,
    "esModuleInterop": true,
    "skipLibCheck": true
  },
  "include": ["src/**/*"]
}"
    },
    {
      "path": "factory-system/src/types.ts",
      "content": "export interface Component {
  id: string;
  name: string;
  type: string;
  properties: Record<string, any>;
}

export interface Station {
  id: string;
  name: string;
  capabilities: string[];
  status: 'idle' | 'busy' | 'offline';
  currentProductId?: string;
}

export interface Product {
  id: string;
  sku: string;
  name: string;
  requiredComponents: string[];
}

export interface Routing {
  productId: string;
  steps: { 
    stationId: string; 
    operation: string; 
    sequence: number; 
  }[];
}
"
    },
    {
      "path": "factory-system/src/index.ts",
      "content": "export * from './types';
"
    }
  ],
  "notes": "Created factory-system project layout with core types for Component, Station, Product, and Routing to satisfy layout and API contract validators."
}
